begin

delete from perf_T_warnset where type in ('selfresultdept','selfscoredept');

INSERT INTO v_perf_T_warnset(guid,code,name,type,warnsql,updatetime,createtime,year,province) VALUES 
('112F83BC5F672456DBD010DF9D6BC976','selfresultdept','自评结论-部门','selfresultdept','select case when nvl(s.score,0) + nvl(a.bgtscore,0) >= 90 then ''优'' when (nvl(s.score, 0) + nvl(a.bgtscore,0) >= 80 and nvl(s.score, 0) + nvl(a.bgtscore,0) < 90) then ''良'' when (nvl(s.score, 0) + nvl(a.bgtscore,0) >= 60 and nvl(s.score, 0) + nvl(a.bgtscore,0) < 80) then ''中'' when nvl(s.score, 0) + nvl(a.bgtscore,0) < 60 then ''差'' end as value FROM (select c.mainguid, c.agencyguid, sum(c.score) score from V_PERF_T_SELFPERFINDEX c group by c.mainguid, c.agencyguid) s left join (select nvl(nvl(sum(AMT4),0)/decode(nvl(sum(AMT3),1),0,1,nvl(sum(AMT3),1)) * 10, 0) bgtscore, agencyguid from v_perf_t_selfprofund group by agencyguid) a on a.agencyguid = ''#agencyguid#'' where s.mainguid = ''#mainguid#''','20220209165444',NULL,'2016','87')
,('6BDCD855C9FAAD2E937EA6C3DED01F6A','selfscoredept','自评得分-部门','selfscoredept','select to_char(nvl(s.score, 0) + nvl(a.bgtscore,0),''FM990.00'') as value FROM (select c.mainguid, c.agencyguid, sum(c.score) score from V_PERF_T_SELFPERFINDEX c group by c.mainguid, c.agencyguid) s left join (select nvl(nvl(sum(AMT4),0)/decode(nvl(sum(AMT3),1),0,1,nvl(sum(AMT3),1)) * 10, 0) bgtscore, agencyguid from v_perf_t_selfprofund group by agencyguid) a on a.agencyguid = ''#agencyguid#'' where s.mainguid = ''#mainguid#'' union select ''0'' as value from dual where not exists (select 1 from V_PERF_T_SELFPERFINDEX where mainguid = ''#mainguid#'' and agencyguid = ''#agencyguid#'') ','20220209165444',NULL,'2016','87')
